import { IMessageComposer } from '@nitrots/nitro-renderer';

export class StartWorkComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(startWorking: boolean) {
        this._data = [startWorking];
        console.log(`Packet StartWorkComposer sent. Starting: ${startWorking}`);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}